def gen(rng, size):
    sx = rng.randint(1, 20)
    sy = rng.randint(1, 20)
    x, y = sx, sy
    steps = rng.randint(0, min(30, max(1, size)))
    for _ in range(steps):
        if rng.random() < 0.5:
            y = x + y
        else:
            x = x + y
        if x > 5000 or y > 5000:
            x, y = sx, sy
            break
    return [sx, sy, x, y]

