import sys

class Solution:
    def reachingPoints(self, sx, sy, tx, ty):
        # Independent recursion: a target (x, y) is reachable iff its unique
        # predecessor is reachable. The predecessor subtracts the smaller axis
        # from the larger; we recurse on that single parent. A guard handles the
        # case where one axis already equals its start (then only repeated
        # addition along the other axis remains).
        sys.setrecursionlimit(1000000)
        def rec(x, y):
            if x < sx or y < sy:
                return False
            if x == sx and y == sy:
                return True
            if x == sx:
                return (y - sy) % sx == 0
            if y == sy:
                return (x - sx) % sy == 0
            if x > y:
                return rec(x - y, y)
            if y > x:
                return rec(x, y - x)
            return False
        # iterative form of the same recursion to avoid deep stacks
        x, y = tx, ty
        while True:
            if x < sx or y < sy:
                return False
            if x == sx and y == sy:
                return True
            if x == sx:
                return (y - sy) % sx == 0
            if y == sy:
                return (x - sx) % sy == 0
            if x > y:
                x -= y
            elif y > x:
                y -= x
            else:
                return False

