class Solution:
    def reachingPoints(self, sx, sy, tx, ty):
        while tx >= sx and ty >= sy:
            if tx == sx and ty == sy:
                return True
            if tx > ty:
                if ty > sy:
                    tx %= ty
                else:
                    return (tx - sx) % ty == 0
            elif ty > tx:
                if tx > sx:
                    ty %= tx
                else:
                    return (ty - sy) % tx == 0
            else:
                return False
        return False

